-- Insert Lat Pulldown
INSERT INTO exercise (user_id, body_part, name, sort_order)
VALUES (NULL, 'back', 'Lat Pulldown', 1);

-- Reorder existing back exercises
UPDATE exercise SET sort_order = 2 WHERE user_id IS NULL AND body_part = 'back' AND name = 'Barbell Row';
UPDATE exercise SET sort_order = 3 WHERE user_id IS NULL AND body_part = 'back' AND name = 'Machine Row';

UPDATE exercise
SET name = 'Triceps Curl'
WHERE user_id IS NULL AND body_part = 'arms' AND name = 'Triceps Pushdown';
